# solution.py
"""Team_Collaboration_Manager - a thread-safe, in-memory collaboration core.

This module implements the back-end domain logic for a collaborative
workspace where teams manage users, projects, tasks, messaging,
performance dashboards and exportable reports.

The original task brief is framed as a "Music_Collaborator" web application,
but the binding contract for this deliverable is ``test_solution.py`` which
exercises a ``TeamCollaborationManager`` facade.  The same engineering
principles apply: clean separation of concerns, defensive validation,
deterministic time injection (for testability), copy-on-read isolation so
callers cannot mutate internal state, and a single shared re-entrant lock
that makes every public operation safe under concurrent access.

Only the Python standard library is used.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Authorization role attached to a user account."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    """Lifecycle state of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportType(Enum):
    """The kind of analytical report produced by the manager."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


class ReportFormat(Enum):
    """Supported serialization formats for an exported report."""

    CSV = "csv"
    PDF = "pdf"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when supplied input fails a validation rule."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current system state."""


# ---------------------------------------------------------------------------
# Domain entities
# ---------------------------------------------------------------------------
@dataclass
class User:
    """A registered member of the workspace."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A collaborative project owned by a user."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    """A unit of work that lives inside a project."""

    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    created_at: datetime
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None


@dataclass
class Attachment:
    """Metadata describing a file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    """A chat message scoped to either a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    created_at: datetime
    attachments: List[Attachment] = field(default_factory=list)
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """A peer rating awarded by one user to another."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal stores
#
# Each store owns one slice of the domain data.  Every store shares the *same*
# re-entrant lock as the manager so that the whole system can be guarded by a
# single critical section while still exposing a clean, segmented API surface.
# ---------------------------------------------------------------------------
class _BaseStore:
    """Common base giving every store the shared lock."""

    def __init__(self, lock: threading.RLock) -> None:
        self._lock = lock


class _UserStore(_BaseStore):
    def __init__(self, lock: threading.RLock) -> None:
        super().__init__(lock)
        self.items: Dict[int, User] = {}
        self.by_username: Dict[str, int] = {}
        self.by_email: Dict[str, int] = {}


class _ProjectStore(_BaseStore):
    def __init__(self, lock: threading.RLock) -> None:
        super().__init__(lock)
        self.items: Dict[int, Project] = {}


class _TaskStore(_BaseStore):
    def __init__(self, lock: threading.RLock) -> None:
        super().__init__(lock)
        self.items: Dict[int, Task] = {}
        self.by_project: Dict[int, List[int]] = {}
        self.by_assignee: Dict[int, List[int]] = {}


class _MessageStore(_BaseStore):
    def __init__(self, lock: threading.RLock) -> None:
        super().__init__(lock)
        self.items: Dict[int, Message] = {}
        self.by_project: Dict[int, List[int]] = {}
        self.by_task: Dict[int, List[int]] = {}


class _PerformanceStore(_BaseStore):
    def __init__(self, lock: threading.RLock) -> None:
        super().__init__(lock)
        self.ratings: Dict[int, Rating] = {}
        self.by_ratee: Dict[int, List[int]] = {}


class _ReportStore(_BaseStore):
    """Stateless report namespace; present so it can share the lock."""


# ---------------------------------------------------------------------------
# Index helpers
# ---------------------------------------------------------------------------
def _index_add(index: Dict[int, List[int]], key: int, value: int) -> None:
    index.setdefault(key, []).append(value)


def _index_remove(index: Dict[int, List[int]], key: int, value: int) -> None:
    bucket = index.get(key)
    if bucket and value in bucket:
        bucket.remove(value)
        if not bucket:
            del index[key]


# ---------------------------------------------------------------------------
# Manager facade
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Thread-safe in-memory facade over the collaboration domain.

    Parameters
    ----------
    now:
        A zero-argument callable returning the "current" :class:`datetime`.
        Injecting a clock makes time-dependent behaviour deterministic in
        tests.  Defaults to :func:`datetime.now`.
    """

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._lock = threading.RLock()
        self._now: Callable[[], datetime] = now if now is not None else datetime.now
        self._id_counter = 0

        # Segmented stores all share the one lock instance.
        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)

    # -- internal utilities -------------------------------------------------
    def _next_id(self) -> int:
        self._id_counter += 1
        return self._id_counter

    @staticmethod
    def _copy(obj):
        return copy.deepcopy(obj)

    def _require_user(self, user_id: int) -> User:
        user = self.users.items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id: int) -> Project:
        project = self.projects.items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id: int) -> Task:
        task = self.tasks.items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id: int) -> Message:
        message = self.messages.items.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    @staticmethod
    def _validate_email(email: str) -> str:
        if email is None or not email.strip() or "@" not in email:
            raise ValidationError("invalid email")
        return email.strip()

    @staticmethod
    def _validate_non_empty(value: str, label: str) -> str:
        if value is None or not value.strip():
            raise ValidationError("{0} must not be empty".format(label))
        return value.strip()

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(
        self, username: str, email: str, role: UserRole = UserRole.MEMBER
    ) -> User:
        with self._lock:
            username = self._validate_non_empty(username, "username")
            email = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("invalid role")
            if username in self.users.by_username:
                raise DuplicateError("username already in use")
            if email in self.users.by_email:
                raise DuplicateError("email already in use")

            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users.items[user.id] = user
            self.users.by_username[username] = user.id
            self.users.by_email[email] = user.id
            return self._copy(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            return self._copy(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return [
                self._copy(self.users.items[i])
                for i in sorted(self.users.items)
            ]

    def update_user(
        self,
        user_id: int,
        username: Optional[str] = None,
        email: Optional[str] = None,
        role: Optional[UserRole] = None,
    ) -> User:
        with self._lock:
            user = self._require_user(user_id)

            if username is not None:
                username = self._validate_non_empty(username, "username")
                existing = self.users.by_username.get(username)
                if existing is not None and existing != user_id:
                    raise DuplicateError("username already in use")

            if email is not None:
                email = self._validate_email(email)
                existing = self.users.by_email.get(email)
                if existing is not None and existing != user_id:
                    raise DuplicateError("email already in use")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("invalid role")

            if username is not None and username != user.username:
                del self.users.by_username[user.username]
                self.users.by_username[username] = user_id
                user.username = username

            if email is not None and email != user.email:
                del self.users.by_email[user.email]
                self.users.by_email[email] = user_id
                user.email = email

            if role is not None:
                user.role = role

            return self._copy(user)

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            user = self._require_user(user_id)

            for project in self.projects.items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns one or more projects")

            for task_id in self.tasks.by_assignee.get(user_id, []):
                task = self.tasks.items.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open assigned tasks")

            self.tasks.by_assignee.pop(user_id, None)
            del self.users.items[user_id]
            self.users.by_username.pop(user.username, None)
            self.users.by_email.pop(user.email, None)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(
        self,
        name: str,
        start_date: datetime,
        end_date: datetime,
        owner_id: int,
        description: str = "",
    ) -> Project:
        with self._lock:
            name = self._validate_non_empty(name, "name")
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")
            self._require_user(owner_id)

            project = Project(
                id=self._next_id(),
                name=name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self.projects.items[project.id] = project
            return self._copy(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            return self._copy(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                self._copy(self.projects.items[i])
                for i in sorted(self.projects.items)
            ]

    def update_project(
        self,
        project_id: int,
        name: Optional[str] = None,
        description: Optional[str] = None,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
    ) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            if name is not None:
                name = self._validate_non_empty(name, "name")

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")

            if name is not None:
                project.name = name
            if description is not None:
                project.description = description
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date

            return self._copy(project)

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            self._require_project(project_id)

            task_ids = list(self.tasks.by_project.get(project_id, []))

            # Cascade: remove messages tied to the project or its tasks.
            doomed_messages = set(self.messages.by_project.get(project_id, []))
            for task_id in task_ids:
                doomed_messages.update(self.messages.by_task.get(task_id, []))
            for message_id in doomed_messages:
                self._remove_message(message_id)

            # Cascade: remove tasks and free their assignee indexes.
            for task_id in task_ids:
                task = self.tasks.items.pop(task_id, None)
                if task is not None and task.assignee_id is not None:
                    _index_remove(
                        self.tasks.by_assignee, task.assignee_id, task_id
                    )
            self.tasks.by_project.pop(project_id, None)

            del self.projects.items[project_id]

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(
        self,
        project_id: int,
        title: str,
        assignee_id: Optional[int] = None,
        deadline: Optional[datetime] = None,
    ) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            title = self._validate_non_empty(title, "title")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start")
            if assignee_id is not None:
                self._require_user(assignee_id)

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._now(),
            )
            self.tasks.items[task.id] = task
            _index_add(self.tasks.by_project, project_id, task.id)
            if assignee_id is not None:
                _index_add(self.tasks.by_assignee, assignee_id, task.id)
            return self._copy(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            return self._copy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self.tasks.by_project.get(project_id, []))
            return [self._copy(self.tasks.items[i]) for i in ids]

    def list_tasks_by_assignee(self, user_id: int) -> List[Task]:
        with self._lock:
            self._require_user(user_id)
            ids = sorted(self.tasks.by_assignee.get(user_id, []))
            return [self._copy(self.tasks.items[i]) for i in ids]

    def _set_assignee(self, task: Task, new_assignee_id: Optional[int]) -> None:
        if task.assignee_id == new_assignee_id:
            return
        if task.assignee_id is not None:
            _index_remove(self.tasks.by_assignee, task.assignee_id, task.id)
        if new_assignee_id is not None:
            _index_add(self.tasks.by_assignee, new_assignee_id, task.id)
        task.assignee_id = new_assignee_id

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return self._copy(task)

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return self._copy(task)

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return self._copy(task)

    def set_deadline(
        self, task_id: int, deadline: Optional[datetime]
    ) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self._require_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError(
                        "deadline must not precede project start"
                    )
            task.deadline = deadline
            return self._copy(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("invalid status")
            task = self._require_task(task_id)
            now = self._now()

            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None

            task.status = status
            return self._copy(task)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def _build_attachment(
        self, filename: str, data: bytes, uploaded_by: int
    ) -> Attachment:
        if filename is None or not str(filename).strip():
            raise ValidationError("attachment filename must not be empty")
        size = len(data) if data is not None else 0
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=uploaded_by,
            uploaded_at=self._now(),
        )

    def post_message(
        self,
        author_id: int,
        body: str,
        project_id: Optional[int] = None,
        task_id: Optional[int] = None,
        parent_id: Optional[int] = None,
        attachments: Optional[List[Tuple[str, bytes]]] = None,
    ) -> Message:
        with self._lock:
            self._require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)

            attachment_specs = attachments or []
            has_body = bool(body and body.strip())
            if not has_body and not attachment_specs:
                raise ValidationError("message body or attachment required")

            if parent_id is not None:
                self._require_message(parent_id)

            built = [
                self._build_attachment(name, data, author_id)
                for name, data in attachment_specs
            ]

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body if body is not None else "",
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                created_at=self._now(),
                attachments=built,
                edited_at=None,
            )
            self.messages.items[message.id] = message
            if project_id is not None:
                _index_add(self.messages.by_project, project_id, message.id)
            if task_id is not None:
                _index_add(self.messages.by_task, task_id, message.id)
            return self._copy(message)

    def edit_message(
        self, message_id: int, editor_id: int, new_body: str
    ) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            has_body = bool(new_body and new_body.strip())
            if not has_body and not message.attachments:
                raise ValidationError("message body or attachment required")
            message.body = new_body if new_body is not None else ""
            message.edited_at = self._now()
            return self._copy(message)

    def add_attachment(
        self, message_id: int, user_id: int, filename: str, data: bytes
    ) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError(
                    "only the author may add attachments"
                )
            attachment = self._build_attachment(filename, data, user_id)
            message.attachments.append(attachment)
            return self._copy(message)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self.messages.by_project.get(project_id, []))
            return [self._copy(self.messages.items[i]) for i in ids]

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            ids = sorted(self.messages.by_task.get(task_id, []))
            return [self._copy(self.messages.items[i]) for i in ids]

    def _remove_message(self, message_id: int) -> None:
        message = self.messages.items.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:
            _index_remove(
                self.messages.by_project, message.project_id, message_id
            )
        if message.task_id is not None:
            _index_remove(self.messages.by_task, message.task_id, message_id)

    def delete_message(self, message_id: int, user_id: int) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError(
                    "only the author may delete a message"
                )
            self._remove_message(message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def _assigned_tasks(self, user_id: int) -> List[Task]:
        return [
            self.tasks.items[i]
            for i in self.tasks.by_assignee.get(user_id, [])
            if i in self.tasks.items
        ]

    @staticmethod
    def _completion_time(task: Task) -> Optional[float]:
        if task.started_at is not None and task.completed_at is not None:
            return (task.completed_at - task.started_at).total_seconds()
        return None

    @classmethod
    def _stats_from_tasks(cls, tasks: List[Task]) -> Dict[str, object]:
        total = len(tasks)
        completed = [t for t in tasks if t.status == TaskStatus.COMPLETED]
        in_progress = [t for t in tasks if t.status == TaskStatus.IN_PROGRESS]
        not_started = [t for t in tasks if t.status == TaskStatus.NOT_STARTED]
        rate = (len(completed) / total) if total else 0.0
        durations = [
            cls._completion_time(t)
            for t in completed
            if cls._completion_time(t) is not None
        ]
        average = (sum(durations) / len(durations)) if durations else None
        return {
            "total": total,
            "completed": len(completed),
            "in_progress": len(in_progress),
            "not_started": len(not_started),
            "completion_rate": rate,
            "average_completion_time": average,
        }

    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._require_user(user_id)
            stats = self._stats_from_tasks(self._assigned_tasks(user_id))
            return float(stats["completion_rate"])

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            stats = self._stats_from_tasks(self._assigned_tasks(user_id))
            return stats["average_completion_time"]

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._require_task(task_id)

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance.ratings[rating.id] = rating
            _index_add(self.performance.by_ratee, ratee_id, rating.id)
            return self._copy(rating)

    def _ratings_for(self, user_id: int) -> List[Rating]:
        return [
            self.performance.ratings[i]
            for i in sorted(self.performance.by_ratee.get(user_id, []))
            if i in self.performance.ratings
        ]

    def get_ratings_summary(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [self._copy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            self._require_user(user_id)
            stats = self._stats_from_tasks(self._assigned_tasks(user_id))
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": stats["total"],
                "completed_tasks": stats["completed"],
                "in_progress_tasks": stats["in_progress"],
                "not_started_tasks": stats["not_started"],
                "completion_rate": stats["completion_rate"],
                "average_completion_time": stats["average_completion_time"],
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id: int) -> Dict[str, object]:
        with self._lock:
            self._require_project(project_id)
            tasks = [
                self.tasks.items[i]
                for i in self.tasks.by_project.get(project_id, [])
            ]
            total = len(tasks)

            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1

            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = (completed / total) if total else 0.0

            now = self._now()
            overdue = sum(
                1
                for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )

            per_assignee: Dict[int, Dict[str, object]] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id,
                    {"total": 0, "completed": 0},
                )
                bucket["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
                "generated_at": now,
            }

    def team_performance_report(
        self, project_id: Optional[int] = None
    ) -> Dict[str, object]:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                scope = [
                    self.tasks.items[i]
                    for i in self.tasks.by_project.get(project_id, [])
                ]
            else:
                scope = list(self.tasks.items.values())

            by_user: Dict[int, List[Task]] = {}
            for task in scope:
                if task.assignee_id is None:
                    continue
                by_user.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(by_user):
                stats = self._stats_from_tasks(by_user[user_id])
                rows.append(
                    {
                        "user_id": user_id,
                        "total_tasks": stats["total"],
                        "completed_tasks": stats["completed"],
                        "completion_rate": stats["completion_rate"],
                        "average_completion_time": stats[
                            "average_completion_time"
                        ],
                    }
                )

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
                "generated_at": self._now(),
            }

    def individual_performance_report(
        self, user_id: int
    ) -> Dict[str, object]:
        with self._lock:
            self._require_user(user_id)
            tasks = self._assigned_tasks(user_id)
            stats = self._stats_from_tasks(tasks)
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": stats["total"],
                "completed_tasks": stats["completed"],
                "in_progress_tasks": stats["in_progress"],
                "not_started_tasks": stats["not_started"],
                "completion_rate": stats["completion_rate"],
                "average_completion_time": stats["average_completion_time"],
                "tasks": [self._copy(t) for t in sorted(tasks, key=lambda t: t.id)],
            }

    # ------------------------------------------------------------------
    # Report export
    # ------------------------------------------------------------------
    def export_report(self, report: Dict[str, object], fmt: ReportFormat):
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a mapping")
        if fmt == ReportFormat.CSV:
            return self._export_csv(report)
        return self._export_pdf(report)

    @staticmethod
    def _export_csv(report: Dict[str, object]) -> str:
        output = io.StringIO()
        writer = csv.writer(output)

        rows = report.get("rows")
        if isinstance(rows, list):
            columns: List[str] = []
            for row in rows:
                if isinstance(row, dict):
                    for key in row:
                        if key not in columns:
                            columns.append(key)
            if not columns:
                writer.writerow(["report_type"])
                writer.writerow([report.get("report_type", "")])
            else:
                writer.writerow(columns)
                for row in rows:
                    writer.writerow(
                        ["" if row.get(c) is None else row.get(c) for c in columns]
                    )
        else:
            keys = [
                k
                for k, v in report.items()
                if not isinstance(v, (dict, list))
            ]
            if not keys:
                keys = list(report.keys())
            writer.writerow(keys)
            writer.writerow(
                ["" if report.get(k) is None else report.get(k) for k in keys]
            )

        return output.getvalue()

    @staticmethod
    def _report_to_lines(report: Dict[str, object]) -> List[str]:
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, dict):
                lines.append("{0}:".format(key))
                for sub_key, sub_value in value.items():
                    lines.append("  {0}: {1}".format(sub_key, sub_value))
            elif isinstance(value, list):
                lines.append("{0}: {1} item(s)".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, value))
        return lines

    @classmethod
    def _export_pdf(cls, report: Dict[str, object]) -> bytes:
        lines = cls._report_to_lines(report)

        content_parts = ["BT", "/F1 12 Tf", "72 720 Td", "14 TL"]
        first = True
        for line in lines:
            safe = (
                str(line)
                .replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )
            if not first:
                content_parts.append("T*")
            content_parts.append("({0}) Tj".format(safe))
            first = False
        content_parts.append("ET")
        content = "\n".join(content_parts)

        objects = [
            "<< /Type /Catalog /Pages 2 0 R >>",
            "<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (
                "<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
                "/Resources << /Font << /F1 4 0 R >> >> /Contents 5 0 R >>"
            ),
            "<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
            "<< /Length {0} >>\nstream\n{1}\nendstream".format(
                len(content), content
            ),
        ]

        pdf = "%PDF-1.4\n"
        offsets = []
        for index, obj in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += "{0} 0 obj\n{1}\nendobj\n".format(index, obj)

        xref_pos = len(pdf)
        pdf += "xref\n0 {0}\n".format(len(objects) + 1)
        pdf += "0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset)
        pdf += (
            "trailer\n<< /Size {0} /Root 1 0 R >>\nstartxref\n{1}\n%%EOF".format(
                len(objects) + 1, xref_pos
            )
        )
        return pdf.encode("latin-1")


